30: // ConfigAffectsProxy checks if a pushEv will affect a specified proxy. That means whether the push will be performed
31: // towards the proxy.
32: func ConfigAffectsProxy(req *model.PushRequest, proxy *model.Proxy) bool {
33: 	// Empty changes means "all" to get a backward compatibility.
34: 	if len(req.ConfigsUpdated) == 0 {
35: 		return true
36: 	}
37: 
38: 	for config := range req.ConfigsUpdated {
39: 		affected := true
40: 
41: 		// Some configKinds only affect specific proxy types
42: 		if kindAffectedTypes, f := configKindAffectedProxyTypes[config.Kind]; f {
43: 			affected = false
44: 			for _, t := range kindAffectedTypes {
45: 				if t == proxy.Type {
46: 					affected = true
47: 					break
48: 				}
49: 			}
50: 		}
51: 
52: 		if affected && checkProxyDependencies(proxy, config) {
53: 			return true
54: 		}
55: 	}
56: 
57: 	return false
58: }
59: 
60: func checkProxyDependencies(proxy *model.Proxy, config model.ConfigKey) bool {
61: 	// Detailed config dependencies check.
62: 	switch proxy.Type {
63: 	case model.SidecarProxy:
64: 		if proxy.SidecarScope.DependsOnConfig(config) {
65: 			return true
66: 		} else if proxy.PrevSidecarScope != nil && proxy.PrevSidecarScope.DependsOnConfig(config) {
67: 			return true
68: 		}
69: 	default:
70: 		// TODO We'll add the check for other proxy types later.
71: 		return true
72: 	}
73: 	return false
74: }
75: 
76: // DefaultProxyNeedsPush check if a proxy needs push for this push event.
77: func DefaultProxyNeedsPush(proxy *model.Proxy, req *model.PushRequest) bool {
78: 	if ConfigAffectsProxy(req, proxy) {
79: 		return true
80: 	}
81: 
82: 	// If the proxy's service updated, need push for it.
83: 	if len(proxy.ServiceInstances) > 0 && req.ConfigsUpdated != nil {
84: 		svc := proxy.ServiceInstances[0].Service
85: 		if _, ok := req.ConfigsUpdated[model.ConfigKey{
86: 			Kind:      gvk.ServiceEntry,
87: 			Name:      string(svc.Hostname),
88: 			Namespace: svc.Attributes.Namespace,
89: 		}]; ok {
90: 			return true
91: 		}
92: 	}
93: 
94: 	return false
95: }
